item.description:
 &lt;h2 id=&#34;报错内容4000端口已被占用-尝试其他端口&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#报错内容4000端口已被占用-尝试其他端口&#34;&gt;#&lt;/a&gt; 报错内容：4000 端口已被占用。尝试其他端口&lt;/h2&gt;
&lt;h2 id=&#34;port-4000-has-been-used-try-other-port-instead&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#port-4000-has-been-used-try-other-port-instead&#34;&gt;#&lt;/a&gt; Port 4000 has been used. Try other port instead.&lt;/h2&gt;
&lt;figure class=&#34;highlight bash&#34;&gt;&lt;figcaption data-lang=&#34;bash&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;FATAL Port &lt;span class=&#34;token number&#34;&gt;4000&lt;/span&gt; has been used. Try other port instead.&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;2&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;FATAL &lt;span class=&#34;token punctuation&#34;&gt;&amp;#123;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;3&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;  err: Error: listen EADDRINUSE: address already &lt;span class=&#34;token keyword&#34;&gt;in&lt;/span&gt; use :::4000&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;4&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;      at Server.setupListenHandle &lt;span class=&#34;token punctuation&#34;&gt;[&lt;/span&gt;as _listen2&lt;span class=&#34;token punctuation&#34;&gt;]&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;net.js:1331:16&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;5&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;      at listenInCluster &lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;net.js:1379:12&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;6&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;      at Server.listen &lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;net.js:1465:7&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;7&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;      at E:&lt;span class=&#34;token punctuation&#34;&gt;\&lt;/span&gt;Blog&lt;span class=&#34;token punctuation&#34;&gt;\&lt;/span&gt;node_modules&lt;span class=&#34;token punctuation&#34;&gt;\&lt;/span&gt;hexo-server&lt;span class=&#34;token punctuation&#34;&gt;\&lt;/span&gt;lib&lt;span class=&#34;token punctuation&#34;&gt;\&lt;/span&gt;server.js:68:12&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;8&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;      at Promise._execute &lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;E:&lt;span class=&#34;token punctuation&#34;&gt;\&lt;/span&gt;Blog&lt;span class=&#34;token punctuation&#34;&gt;\&lt;/span&gt;node_modules&lt;span class=&#34;token punctuation&#34;&gt;\&lt;/span&gt;bluebird&lt;span class=&#34;token punctuation&#34;&gt;\&lt;/span&gt;js&lt;span class=&#34;token punctuation&#34;&gt;\&lt;/span&gt;release&lt;span class=&#34;token punctuation&#34;&gt;\&lt;/span&gt;debuggability.js:384:9&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;9&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;      at Promise._resolveFromExecutor &lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;E:&lt;span class=&#34;token punctuation&#34;&gt;\&lt;/span&gt;Blog&lt;span class=&#34;token punctuation&#34;&gt;\&lt;/span&gt;node_modules&lt;span class=&#34;token punctuation&#34;&gt;\&lt;/span&gt;bluebird&lt;span class=&#34;token punctuation&#34;&gt;\&lt;/span&gt;js&lt;span class=&#34;token punctuation&#34;&gt;\&lt;/span&gt;release&lt;span class=&#34;token punctuation&#34;&gt;\&lt;/span&gt;promise.js:518:18&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;10&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;      at new Promise &lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;E:&lt;span class=&#34;token punctuation&#34;&gt;\&lt;/span&gt;Blog&lt;span class=&#34;token punctuation&#34;&gt;\&lt;/span&gt;node_modules&lt;span class=&#34;token punctuation&#34;&gt;\&lt;/span&gt;bluebird&lt;span class=&#34;token punctuation&#34;&gt;\&lt;/span&gt;js&lt;span class=&#34;token punctuation&#34;&gt;\&lt;/span&gt;release&lt;span class=&#34;token punctuation&#34;&gt;\&lt;/span&gt;promise.js:103:10&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;11&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;      at checkPort &lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;E:&lt;span class=&#34;token punctuation&#34;&gt;\&lt;/span&gt;Blog&lt;span class=&#34;token punctuation&#34;&gt;\&lt;/span&gt;node_modules&lt;span class=&#34;token punctuation&#34;&gt;\&lt;/span&gt;hexo-server&lt;span class=&#34;token punctuation&#34;&gt;\&lt;/span&gt;lib&lt;span class=&#34;token punctuation&#34;&gt;\&lt;/span&gt;server.js:65:10&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;12&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;      at Hexo.module.exports &lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;E:&lt;span class=&#34;token punctuation&#34;&gt;\&lt;/span&gt;Blog&lt;span class=&#34;token punctuation&#34;&gt;\&lt;/span&gt;node_modules&lt;span class=&#34;token punctuation&#34;&gt;\&lt;/span&gt;hexo-server&lt;span class=&#34;token punctuation&#34;&gt;\&lt;/span&gt;lib&lt;span class=&#34;token punctuation&#34;&gt;\&lt;/span&gt;server.js:17:10&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;13&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;      at Hexo.tryCatcher &lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;E:&lt;span class=&#34;token punctuation&#34;&gt;\&lt;/span&gt;Blog&lt;span class=&#34;token punctuation&#34;&gt;\&lt;/span&gt;node_modules&lt;span class=&#34;token punctuation&#34;&gt;\&lt;/span&gt;bluebird&lt;span class=&#34;token punctuation&#34;&gt;\&lt;/span&gt;js&lt;span class=&#34;token punctuation&#34;&gt;\&lt;/span&gt;release&lt;span class=&#34;token punctuation&#34;&gt;\&lt;/span&gt;util.js:16:23&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;14&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;      at Hexo.&lt;span class=&#34;token operator&#34;&gt;&amp;lt;&lt;/span&gt;anonymous&lt;span class=&#34;token operator&#34;&gt;&gt;&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;E:&lt;span class=&#34;token punctuation&#34;&gt;\&lt;/span&gt;Blog&lt;span class=&#34;token punctuation&#34;&gt;\&lt;/span&gt;node_modules&lt;span class=&#34;token punctuation&#34;&gt;\&lt;/span&gt;bluebird&lt;span class=&#34;token punctuation&#34;&gt;\&lt;/span&gt;js&lt;span class=&#34;token punctuation&#34;&gt;\&lt;/span&gt;release&lt;span class=&#34;token punctuation&#34;&gt;\&lt;/span&gt;method.js:15:34&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;15&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;      at Hexo.call &lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;E:&lt;span class=&#34;token punctuation&#34;&gt;\&lt;/span&gt;Blog&lt;span class=&#34;token punctuation&#34;&gt;\&lt;/span&gt;node_modules&lt;span class=&#34;token punctuation&#34;&gt;\&lt;/span&gt;hexo&lt;span class=&#34;token punctuation&#34;&gt;\&lt;/span&gt;lib&lt;span class=&#34;token punctuation&#34;&gt;\&lt;/span&gt;hexo&lt;span class=&#34;token punctuation&#34;&gt;\&lt;/span&gt;index.js:258:27&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;16&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;      at E:&lt;span class=&#34;token punctuation&#34;&gt;\&lt;/span&gt;studyAPP&lt;span class=&#34;token punctuation&#34;&gt;\&lt;/span&gt;node_js&lt;span class=&#34;token punctuation&#34;&gt;\&lt;/span&gt;node_global&lt;span class=&#34;token punctuation&#34;&gt;\&lt;/span&gt;node_modules&lt;span class=&#34;token punctuation&#34;&gt;\&lt;/span&gt;hexo-cli&lt;span class=&#34;token punctuation&#34;&gt;\&lt;/span&gt;lib&lt;span class=&#34;token punctuation&#34;&gt;\&lt;/span&gt;hexo.js:60:17&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;17&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;      at tryCatcher &lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;E:&lt;span class=&#34;token punctuation&#34;&gt;\&lt;/span&gt;studyAPP&lt;span class=&#34;token punctuation&#34;&gt;\&lt;/span&gt;node_js&lt;span class=&#34;token punctuation&#34;&gt;\&lt;/span&gt;node_global&lt;span class=&#34;token punctuation&#34;&gt;\&lt;/span&gt;node_modules&lt;span class=&#34;token punctuation&#34;&gt;\&lt;/span&gt;hexo-cli&lt;span class=&#34;token punctuation&#34;&gt;\&lt;/span&gt;node_modules&lt;span class=&#34;token punctuation&#34;&gt;\&lt;/span&gt;bluebird&lt;span class=&#34;token punctuation&#34;&gt;\&lt;/span&gt;js&lt;span class=&#34;token punctuation&#34;&gt;\&lt;/span&gt;release&lt;span class=&#34;token punctuation&#34;&gt;\&lt;/span&gt;util.js:16:23&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;18&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;      at Promise._settlePromiseFromHandler &lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;E:&lt;span class=&#34;token punctuation&#34;&gt;\&lt;/span&gt;studyAPP&lt;span class=&#34;token punctuation&#34;&gt;\&lt;/span&gt;node_js&lt;span class=&#34;token punctuation&#34;&gt;\&lt;/span&gt;node_global&lt;span class=&#34;token punctuation&#34;&gt;\&lt;/span&gt;node_modules&lt;span class=&#34;token punctuation&#34;&gt;\&lt;/span&gt;hexo-cli&lt;span class=&#34;token punctuation&#34;&gt;\&lt;/span&gt;node_modules&lt;span class=&#34;token punctuation&#34;&gt;\&lt;/span&gt;bluebird&lt;span class=&#34;token punctuation&#34;&gt;\&lt;/span&gt;js&lt;span class=&#34;token punctuation&#34;&gt;\&lt;/span&gt;release&lt;span class=&#34;token punctuation&#34;&gt;\&lt;/span&gt;promise.js:547:31&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;19&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;      at Promise._settlePromise &lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;E:&lt;span class=&#34;token punctuation&#34;&gt;\&lt;/span&gt;studyAPP&lt;span class=&#34;token punctuation&#34;&gt;\&lt;/span&gt;node_js&lt;span class=&#34;token punctuation&#34;&gt;\&lt;/span&gt;node_global&lt;span class=&#34;token punctuation&#34;&gt;\&lt;/span&gt;node_modules&lt;span class=&#34;token punctuation&#34;&gt;\&lt;/span&gt;hexo-cli&lt;span class=&#34;token punctuation&#34;&gt;\&lt;/span&gt;node_modules&lt;span class=&#34;token punctuation&#34;&gt;\&lt;/span&gt;bluebird&lt;span class=&#34;token punctuation&#34;&gt;\&lt;/span&gt;js&lt;span class=&#34;token punctuation&#34;&gt;\&lt;/span&gt;release&lt;span class=&#34;token punctuation&#34;&gt;\&lt;/span&gt;promise.js:604:18&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;20&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;      at Promise._settlePromise0 &lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;E:&lt;span class=&#34;token punctuation&#34;&gt;\&lt;/span&gt;studyAPP&lt;span class=&#34;token punctuation&#34;&gt;\&lt;/span&gt;node_js&lt;span class=&#34;token punctuation&#34;&gt;\&lt;/span&gt;node_global&lt;span class=&#34;token punctuation&#34;&gt;\&lt;/span&gt;node_modules&lt;span class=&#34;token punctuation&#34;&gt;\&lt;/span&gt;hexo-cli&lt;span class=&#34;token punctuation&#34;&gt;\&lt;/span&gt;node_modules&lt;span class=&#34;token punctuation&#34;&gt;\&lt;/span&gt;bluebird&lt;span class=&#34;token punctuation&#34;&gt;\&lt;/span&gt;js&lt;span class=&#34;token punctuation&#34;&gt;\&lt;/span&gt;release&lt;span class=&#34;token punctuation&#34;&gt;\&lt;/span&gt;promise.js:649:10&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;21&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;      at Promise._settlePromises &lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;E:&lt;span class=&#34;token punctuation&#34;&gt;\&lt;/span&gt;studyAPP&lt;span class=&#34;token punctuation&#34;&gt;\&lt;/span&gt;node_js&lt;span class=&#34;token punctuation&#34;&gt;\&lt;/span&gt;node_global&lt;span class=&#34;token punctuation&#34;&gt;\&lt;/span&gt;node_modules&lt;span class=&#34;token punctuation&#34;&gt;\&lt;/span&gt;hexo-cli&lt;span class=&#34;token punctuation&#34;&gt;\&lt;/span&gt;node_modules&lt;span class=&#34;token punctuation&#34;&gt;\&lt;/span&gt;bluebird&lt;span class=&#34;token punctuation&#34;&gt;\&lt;/span&gt;js&lt;span class=&#34;token punctuation&#34;&gt;\&lt;/span&gt;release&lt;span class=&#34;token punctuation&#34;&gt;\&lt;/span&gt;promise.js:729:18&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;22&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;      at _drainQueueStep &lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;E:&lt;span class=&#34;token punctuation&#34;&gt;\&lt;/span&gt;studyAPP&lt;span class=&#34;token punctuation&#34;&gt;\&lt;/span&gt;node_js&lt;span class=&#34;token punctuation&#34;&gt;\&lt;/span&gt;node_global&lt;span class=&#34;token punctuation&#34;&gt;\&lt;/span&gt;node_modules&lt;span class=&#34;token punctuation&#34;&gt;\&lt;/span&gt;hexo-cli&lt;span class=&#34;token punctuation&#34;&gt;\&lt;/span&gt;node_modules&lt;span class=&#34;token punctuation&#34;&gt;\&lt;/span&gt;bluebird&lt;span class=&#34;token punctuation&#34;&gt;\&lt;/span&gt;js&lt;span class=&#34;token punctuation&#34;&gt;\&lt;/span&gt;release&lt;span class=&#34;token punctuation&#34;&gt;\&lt;/span&gt;async.js:93:12&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;23&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;      at _drainQueue &lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;E:&lt;span class=&#34;token punctuation&#34;&gt;\&lt;/span&gt;studyAPP&lt;span class=&#34;token punctuation&#34;&gt;\&lt;/span&gt;node_js&lt;span class=&#34;token punctuation&#34;&gt;\&lt;/span&gt;node_global&lt;span class=&#34;token punctuation&#34;&gt;\&lt;/span&gt;node_modules&lt;span class=&#34;token punctuation&#34;&gt;\&lt;/span&gt;hexo-cli&lt;span class=&#34;token punctuation&#34;&gt;\&lt;/span&gt;node_modules&lt;span class=&#34;token punctuation&#34;&gt;\&lt;/span&gt;bluebird&lt;span class=&#34;token punctuation&#34;&gt;\&lt;/span&gt;js&lt;span class=&#34;token punctuation&#34;&gt;\&lt;/span&gt;release&lt;span class=&#34;token punctuation&#34;&gt;\&lt;/span&gt;async.js:86:9&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;24&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;      at Async._drainQueues &lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;E:&lt;span class=&#34;token punctuation&#34;&gt;\&lt;/span&gt;studyAPP&lt;span class=&#34;token punctuation&#34;&gt;\&lt;/span&gt;node_js&lt;span class=&#34;token punctuation&#34;&gt;\&lt;/span&gt;node_global&lt;span class=&#34;token punctuation&#34;&gt;\&lt;/span&gt;node_modules&lt;span class=&#34;token punctuation&#34;&gt;\&lt;/span&gt;hexo-cli&lt;span class=&#34;token punctuation&#34;&gt;\&lt;/span&gt;node_modules&lt;span class=&#34;token punctuation&#34;&gt;\&lt;/span&gt;bluebird&lt;span class=&#34;token punctuation&#34;&gt;\&lt;/span&gt;js&lt;span class=&#34;token punctuation&#34;&gt;\&lt;/span&gt;release&lt;span class=&#34;token punctuation&#34;&gt;\&lt;/span&gt;async.js:102:5&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;25&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;      at Immediate.Async.drainQueues &lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;E:&lt;span class=&#34;token punctuation&#34;&gt;\&lt;/span&gt;studyAPP&lt;span class=&#34;token punctuation&#34;&gt;\&lt;/span&gt;node_js&lt;span class=&#34;token punctuation&#34;&gt;\&lt;/span&gt;node_global&lt;span class=&#34;token punctuation&#34;&gt;\&lt;/span&gt;node_modules&lt;span class=&#34;token punctuation&#34;&gt;\&lt;/span&gt;hexo-cli&lt;span class=&#34;token punctuation&#34;&gt;\&lt;/span&gt;node_modules&lt;span class=&#34;token punctuation&#34;&gt;\&lt;/span&gt;bluebird&lt;span class=&#34;token punctuation&#34;&gt;\&lt;/span&gt;js&lt;span class=&#34;token punctuation&#34;&gt;\&lt;/span&gt;release&lt;span class=&#34;token punctuation&#34;&gt;\&lt;/span&gt;async.js:15:14&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;&amp;#123;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;26&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    code: &lt;span class=&#34;token string&#34;&gt;&#39;EADDRINUSE&#39;&lt;/span&gt;,&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;27&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    errno: -4091,&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;28&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    syscall: &lt;span class=&#34;token string&#34;&gt;&#39;listen&#39;&lt;/span&gt;,&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;29&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    address: &lt;span class=&#34;token string&#34;&gt;&#39;::&#39;&lt;/span&gt;,&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;30&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    port: &lt;span class=&#34;token number&#34;&gt;4000&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;31&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;  &lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;32&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt; Something&#39;s wrong. Maybe you can &lt;span class=&#34;token function&#34;&gt;find&lt;/span&gt; the solution here: %s https://hexo.io/docs/troubleshooting.html&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;p&gt;&lt;img data-src=&#34;https://cdn.jsdelivr.net/gh/0000rookie/imgs/2022050306.jpeg&#34; alt=&#34;&#34;&gt;&lt;/p&gt;
&lt;h2 id=&#34;解决方法&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#解决方法&#34;&gt;#&lt;/a&gt; 解决方法&lt;/h2&gt;
&lt;h3 id=&#34;方法一&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#方法一&#34;&gt;#&lt;/a&gt; 方法一&lt;/h3&gt;
&lt;p&gt;杀掉 &lt;code&gt;4000&lt;/code&gt;  被占用的端口，让 &lt;code&gt;hexo&lt;/code&gt;  运行 &lt;code&gt;4000&lt;/code&gt;  端口&lt;/p&gt;
&lt;figure class=&#34;highlight bash&#34;&gt;&lt;figcaption data-lang=&#34;bash&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token operator&#34;&gt;&gt;&gt;&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;&gt;&lt;/span&gt; &lt;span class=&#34;token function&#34;&gt;netstat&lt;/span&gt; -ano &lt;span class=&#34;token operator&#34;&gt;|&lt;/span&gt; findstr &lt;span class=&#34;token string&#34;&gt;&#34;4000&#34;&lt;/span&gt; &lt;span class=&#34;token comment&#34;&gt;# 查看 4000 端口是什么程序占用&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;2&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token operator&#34;&gt;&gt;&gt;&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;&gt;&lt;/span&gt; taskkill -PID &lt;span class=&#34;token number&#34;&gt;15868&lt;/span&gt; -F				&lt;span class=&#34;token comment&#34;&gt;# 杀掉 4000 端口正在运行的程序&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;p&gt;&lt;img data-src=&#34;https://cdn.jsdelivr.net/gh/0000rookie/imgs/2022050215.jpeg&#34; alt=&#34;&#34;&gt;&lt;/p&gt;
&lt;h3 id=&#34;方法二&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#方法二&#34;&gt;#&lt;/a&gt; 方法二&lt;/h3&gt;
&lt;p&gt;在 &lt;code&gt;_config.yml&lt;/code&gt;  修改 hexo 默认端口，在 &lt;code&gt;hexo s &lt;/code&gt; 的时候就不是 &lt;code&gt;4000&lt;/code&gt;  端口了&lt;/p&gt;
&lt;figure class=&#34;highlight yaml&#34;&gt;&lt;figcaption data-lang=&#34;YAML&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token key atrule&#34;&gt;server&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;:&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;2&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;  &lt;span class=&#34;token key atrule&#34;&gt;port&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;:&lt;/span&gt; &lt;span class=&#34;token number&#34;&gt;4001&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;3&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;  &lt;span class=&#34;token key atrule&#34;&gt;compress&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;:&lt;/span&gt; &lt;span class=&#34;token boolean important&#34;&gt;true&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;4&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;  &lt;span class=&#34;token key atrule&#34;&gt;header&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;:&lt;/span&gt; &lt;span class=&#34;token boolean important&#34;&gt;true&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;h3 id=&#34;方法三&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#方法三&#34;&gt;#&lt;/a&gt; 方法三&lt;/h3&gt;
&lt;p&gt;指定端口运行&lt;/p&gt;
&lt;p&gt;这里指定 5000 端口运行&lt;/p&gt;
&lt;figure class=&#34;highlight bash&#34;&gt;&lt;figcaption data-lang=&#34;bash&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token operator&#34;&gt;&gt;&gt;&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;&gt;&lt;/span&gt; hexo server -p &lt;span class=&#34;token number&#34;&gt;5000&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;

 &lt;h2 id=&#34;warning-retrying-retrytotal4-connectnone-readnone-redirectnone-statusnone-after-connection-broken-by-proxyerrorcannot-connect-to-proxy-oserror0-error-pypisimpleeyed3&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#warning-retrying-retrytotal4-connectnone-readnone-redirectnone-statusnone-after-connection-broken-by-proxyerrorcannot-connect-to-proxy-oserror0-error-pypisimpleeyed3&#34;&gt;#&lt;/a&gt; WARNING: Retrying (Retry(total=4, connect=None, read=None, redirect=None, status=None)) after connection broken by ‘ProxyError(‘Cannot connect to proxy.’, OSError(0, ‘Error’))’: /pypi/simple/eyed3/&lt;/h2&gt;
&lt;p&gt;出现错误如图所示&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;https://cdn.jsdelivr.net/gh/0000rookie/imgs/2022053531.png&#34; alt=&#34;&#34;&gt;&lt;/p&gt;
&lt;h2 id=&#34;解决方法&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#解决方法&#34;&gt;#&lt;/a&gt; 解决方法：&lt;/h2&gt;
&lt;h3 id=&#34;方法一&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#方法一&#34;&gt;#&lt;/a&gt; 方法一&lt;/h3&gt;
&lt;p&gt;关闭你的梯子就解决问题了，哈哈&lt;/p&gt;
&lt;h3 id=&#34;方法二&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#方法二&#34;&gt;#&lt;/a&gt; 方法二&lt;/h3&gt;
&lt;p&gt;指定源下载&lt;/p&gt;
&lt;figure class=&#34;highlight apl&#34;&gt;&lt;figcaption data-lang=&#34;APL&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;pip install requests &lt;span class=&#34;token function&#34;&gt;-&lt;/span&gt;i http&lt;span class=&#34;token dfn builtin&#34;&gt;:&lt;/span&gt;&lt;span class=&#34;token monadic-operator operator&#34;&gt;/&lt;/span&gt;&lt;span class=&#34;token monadic-operator operator&#34;&gt;/&lt;/span&gt;pypi&lt;span class=&#34;token dyadic-operator operator&#34;&gt;.&lt;/span&gt;douban&lt;span class=&#34;token dyadic-operator operator&#34;&gt;.&lt;/span&gt;com&lt;span class=&#34;token monadic-operator operator&#34;&gt;/&lt;/span&gt;simple &lt;span class=&#34;token function&#34;&gt;-&lt;/span&gt;&lt;span class=&#34;token function&#34;&gt;-&lt;/span&gt;trusted&lt;span class=&#34;token function&#34;&gt;-&lt;/span&gt;host pypi&lt;span class=&#34;token dyadic-operator operator&#34;&gt;.&lt;/span&gt;douban&lt;span class=&#34;token dyadic-operator operator&#34;&gt;.&lt;/span&gt;com&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;p&gt;我的源是阿里云的源，我挂了梯子就用不了，关了梯子就可以了。&lt;/p&gt;
&lt;figure class=&#34;highlight apl&#34;&gt;&lt;figcaption data-lang=&#34;APL&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;国内的pip源，如下：&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;2&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;3&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;阿里云 http&lt;span class=&#34;token dfn builtin&#34;&gt;:&lt;/span&gt;&lt;span class=&#34;token monadic-operator operator&#34;&gt;/&lt;/span&gt;&lt;span class=&#34;token monadic-operator operator&#34;&gt;/&lt;/span&gt;mirrors&lt;span class=&#34;token dyadic-operator operator&#34;&gt;.&lt;/span&gt;aliyun&lt;span class=&#34;token dyadic-operator operator&#34;&gt;.&lt;/span&gt;com&lt;span class=&#34;token monadic-operator operator&#34;&gt;/&lt;/span&gt;pypi&lt;span class=&#34;token monadic-operator operator&#34;&gt;/&lt;/span&gt;simple&lt;span class=&#34;token monadic-operator operator&#34;&gt;/&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;4&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;5&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;中国科技大学 https&lt;span class=&#34;token dfn builtin&#34;&gt;:&lt;/span&gt;&lt;span class=&#34;token monadic-operator operator&#34;&gt;/&lt;/span&gt;&lt;span class=&#34;token monadic-operator operator&#34;&gt;/&lt;/span&gt;pypi&lt;span class=&#34;token dyadic-operator operator&#34;&gt;.&lt;/span&gt;mirrors&lt;span class=&#34;token dyadic-operator operator&#34;&gt;.&lt;/span&gt;ustc&lt;span class=&#34;token dyadic-operator operator&#34;&gt;.&lt;/span&gt;edu&lt;span class=&#34;token dyadic-operator operator&#34;&gt;.&lt;/span&gt;cn&lt;span class=&#34;token monadic-operator operator&#34;&gt;/&lt;/span&gt;simple&lt;span class=&#34;token monadic-operator operator&#34;&gt;/&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;6&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;7&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;豆瓣&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;douban&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt; http&lt;span class=&#34;token dfn builtin&#34;&gt;:&lt;/span&gt;&lt;span class=&#34;token monadic-operator operator&#34;&gt;/&lt;/span&gt;&lt;span class=&#34;token monadic-operator operator&#34;&gt;/&lt;/span&gt;pypi&lt;span class=&#34;token dyadic-operator operator&#34;&gt;.&lt;/span&gt;douban&lt;span class=&#34;token dyadic-operator operator&#34;&gt;.&lt;/span&gt;com&lt;span class=&#34;token monadic-operator operator&#34;&gt;/&lt;/span&gt;simple&lt;span class=&#34;token monadic-operator operator&#34;&gt;/&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;8&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;9&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;清华大学 https&lt;span class=&#34;token dfn builtin&#34;&gt;:&lt;/span&gt;&lt;span class=&#34;token monadic-operator operator&#34;&gt;/&lt;/span&gt;&lt;span class=&#34;token monadic-operator operator&#34;&gt;/&lt;/span&gt;pypi&lt;span class=&#34;token dyadic-operator operator&#34;&gt;.&lt;/span&gt;tuna&lt;span class=&#34;token dyadic-operator operator&#34;&gt;.&lt;/span&gt;tsinghua&lt;span class=&#34;token dyadic-operator operator&#34;&gt;.&lt;/span&gt;edu&lt;span class=&#34;token dyadic-operator operator&#34;&gt;.&lt;/span&gt;cn&lt;span class=&#34;token monadic-operator operator&#34;&gt;/&lt;/span&gt;simple&lt;span class=&#34;token monadic-operator operator&#34;&gt;/&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;10&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;11&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;中国科学技术大学 http&lt;span class=&#34;token dfn builtin&#34;&gt;:&lt;/span&gt;&lt;span class=&#34;token monadic-operator operator&#34;&gt;/&lt;/span&gt;&lt;span class=&#34;token monadic-operator operator&#34;&gt;/&lt;/span&gt;pypi&lt;span class=&#34;token dyadic-operator operator&#34;&gt;.&lt;/span&gt;mirrors&lt;span class=&#34;token dyadic-operator operator&#34;&gt;.&lt;/span&gt;ustc&lt;span class=&#34;token dyadic-operator operator&#34;&gt;.&lt;/span&gt;edu&lt;span class=&#34;token dyadic-operator operator&#34;&gt;.&lt;/span&gt;cn&lt;span class=&#34;token monadic-operator operator&#34;&gt;/&lt;/span&gt;simple&lt;span class=&#34;token monadic-operator operator&#34;&gt;/&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;

 &lt;h2 id=&#34;报错内容1&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#报错内容1&#34;&gt;#&lt;/a&gt; 报错内容&lt;sub class=&#34;red&#34;&gt; 1&lt;/sub&gt;&lt;/h2&gt;
&lt;p&gt;[ERROR] Failed to execute goal org.apache.maven.plugins:maven-compiler-plugin:3.1:compile (default-compile) on project lab11: Compilation failure: Compilation failure:&lt;/p&gt;
&lt;p&gt;[ERROR] 不再支持源选项 5。请使用 7 或更高版本。&lt;/p&gt;
&lt;p&gt;[ERROR] 不再支持目标选项 5。请使用 7 或更高版本。&lt;/p&gt;
&lt;h3 id=&#34;解决办法&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#解决办法&#34;&gt;#&lt;/a&gt; 解决办法&lt;/h3&gt;
&lt;p&gt;在 pom.xml 添加插件级可以解决&lt;/p&gt;
&lt;figure class=&#34;highlight xml&#34;&gt;&lt;figcaption data-lang=&#34;XML&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token tag&#34;&gt;&lt;span class=&#34;token tag&#34;&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;lt;&lt;/span&gt;build&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;&gt;&lt;/span&gt;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;2&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;   &lt;span class=&#34;token tag&#34;&gt;&lt;span class=&#34;token tag&#34;&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;lt;&lt;/span&gt;plugins&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;&gt;&lt;/span&gt;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;3&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;       &lt;span class=&#34;token tag&#34;&gt;&lt;span class=&#34;token tag&#34;&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;lt;&lt;/span&gt;plugin&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;&gt;&lt;/span&gt;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;4&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;           &lt;span class=&#34;token tag&#34;&gt;&lt;span class=&#34;token tag&#34;&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;lt;&lt;/span&gt;groupId&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;&gt;&lt;/span&gt;&lt;/span&gt;org.apache.maven.plugins&lt;span class=&#34;token tag&#34;&gt;&lt;span class=&#34;token tag&#34;&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;lt;/&lt;/span&gt;groupId&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;&gt;&lt;/span&gt;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;5&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;           &lt;span class=&#34;token tag&#34;&gt;&lt;span class=&#34;token tag&#34;&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;lt;&lt;/span&gt;artifactId&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;&gt;&lt;/span&gt;&lt;/span&gt;maven-compiler-plugin&lt;span class=&#34;token tag&#34;&gt;&lt;span class=&#34;token tag&#34;&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;lt;/&lt;/span&gt;artifactId&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;&gt;&lt;/span&gt;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;6&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;           &lt;span class=&#34;token tag&#34;&gt;&lt;span class=&#34;token tag&#34;&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;lt;&lt;/span&gt;configuration&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;&gt;&lt;/span&gt;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;7&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;               &lt;span class=&#34;token tag&#34;&gt;&lt;span class=&#34;token tag&#34;&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;lt;&lt;/span&gt;source&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;&gt;&lt;/span&gt;&lt;/span&gt;1.8&lt;span class=&#34;token tag&#34;&gt;&lt;span class=&#34;token tag&#34;&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;lt;/&lt;/span&gt;source&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;&gt;&lt;/span&gt;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;8&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;               &lt;span class=&#34;token tag&#34;&gt;&lt;span class=&#34;token tag&#34;&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;lt;&lt;/span&gt;target&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;&gt;&lt;/span&gt;&lt;/span&gt;1.8&lt;span class=&#34;token tag&#34;&gt;&lt;span class=&#34;token tag&#34;&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;lt;/&lt;/span&gt;target&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;&gt;&lt;/span&gt;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;9&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;               &lt;span class=&#34;token tag&#34;&gt;&lt;span class=&#34;token tag&#34;&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;lt;&lt;/span&gt;encoding&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;&gt;&lt;/span&gt;&lt;/span&gt;UTF-8&lt;span class=&#34;token tag&#34;&gt;&lt;span class=&#34;token tag&#34;&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;lt;/&lt;/span&gt;encoding&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;&gt;&lt;/span&gt;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;10&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;           &lt;span class=&#34;token tag&#34;&gt;&lt;span class=&#34;token tag&#34;&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;lt;/&lt;/span&gt;configuration&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;&gt;&lt;/span&gt;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;11&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;       &lt;span class=&#34;token tag&#34;&gt;&lt;span class=&#34;token tag&#34;&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;lt;/&lt;/span&gt;plugin&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;&gt;&lt;/span&gt;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;12&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;   &lt;span class=&#34;token tag&#34;&gt;&lt;span class=&#34;token tag&#34;&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;lt;/&lt;/span&gt;plugins&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;&gt;&lt;/span&gt;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;13&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token tag&#34;&gt;&lt;span class=&#34;token tag&#34;&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;lt;/&lt;/span&gt;build&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;&gt;&lt;/span&gt;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;h2 id=&#34;报错内容2&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#报错内容2&#34;&gt;#&lt;/a&gt; 报错内容&lt;sub class=&#34;red&#34;&gt; 2&lt;/sub&gt;&lt;/h2&gt;
&lt;p&gt;&lt;img data-src=&#34;https://cdn.jsdelivr.net/gh/0000rookie/imgs/2022051525.jpeg&#34; alt=&#34;&#34;&gt;&lt;/p&gt;
&lt;h3 id=&#34;解决办法-2&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#解决办法-2&#34;&gt;#&lt;/a&gt; 解决办法&lt;/h3&gt;
&lt;p&gt;其实在 pom.xml 依赖有重复了，删掉就没问题了&lt;/p&gt;
&lt;h2 id=&#34;单元测试成功&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#单元测试成功&#34;&gt;#&lt;/a&gt; 单元测试成功&lt;/h2&gt;
&lt;p&gt;&lt;img data-src=&#34;https://cdn.jsdelivr.net/gh/0000rookie/imgs/2022051530.jpeg&#34; alt=&#34;&#34;&gt;&lt;/p&gt;

 &lt;h2 id=&#34;函数1&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#函数1&#34;&gt;#&lt;/a&gt; 函数&lt;sub class=&#34;red&#34;&gt; 1&lt;/sub&gt;&lt;/h2&gt;
&lt;p&gt;&lt;img data-src=&#34;https://cdn.jsdelivr.net/gh/0000rookie/imgs/2022051002.png&#34; alt=&#34;&#34; width=&#34;10%&#34; height=&#34;10%&#34;&gt;&lt;/p&gt;
&lt;figure class=&#34;highlight python&#34;&gt;&lt;figcaption data-lang=&#34;python&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr class=&#34;marked&#34;&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;import&lt;/span&gt; numpy &lt;span class=&#34;token keyword&#34;&gt;as&lt;/span&gt; np&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr class=&#34;marked&#34;&gt;&lt;td data-num=&#34;2&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;import&lt;/span&gt; matplotlib&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;pyplot &lt;span class=&#34;token keyword&#34;&gt;as&lt;/span&gt; plt&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr class=&#34;marked&#34;&gt;&lt;td data-num=&#34;3&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr class=&#34;marked&#34;&gt;&lt;td data-num=&#34;4&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;x &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; np&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;arange&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;-&lt;/span&gt;&lt;span class=&#34;token number&#34;&gt;5&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt;&lt;span class=&#34;token number&#34;&gt;5&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt;&lt;span class=&#34;token number&#34;&gt;0.01&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;	&lt;span class=&#34;token comment&#34;&gt;# 设置 X 的值&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr class=&#34;marked&#34;&gt;&lt;td data-num=&#34;5&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;y &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;token number&#34;&gt;1&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;/&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token number&#34;&gt;1&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;+&lt;/span&gt;np&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;exp&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;-&lt;/span&gt;x&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt; 		&lt;span class=&#34;token comment&#34;&gt;# 设置 Y 的值，一个 Y 都有一个 X 与他对应&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr class=&#34;marked&#34;&gt;&lt;td data-num=&#34;6&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;plt&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;xlim&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;-&lt;/span&gt;&lt;span class=&#34;token number&#34;&gt;6&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt;&lt;span class=&#34;token number&#34;&gt;6&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt; 		&lt;span class=&#34;token comment&#34;&gt;#　设置Ｘ轴的范围&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr class=&#34;marked&#34;&gt;&lt;td data-num=&#34;7&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;plt&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;ylim&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token number&#34;&gt;0.0&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt;&lt;span class=&#34;token number&#34;&gt;1.0&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt; 		&lt;span class=&#34;token comment&#34;&gt;# 设置 Y 轴的范围&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr class=&#34;marked&#34;&gt;&lt;td data-num=&#34;8&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;plt&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;plot&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;x&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt;y&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt; 			&lt;span class=&#34;token comment&#34;&gt;# 将 X、Y 的值添加到面板中&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr class=&#34;marked&#34;&gt;&lt;td data-num=&#34;9&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;plt&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;show&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt; 			&lt;span class=&#34;token comment&#34;&gt;# 显示面板&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;h2 id=&#34;函数2&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#函数2&#34;&gt;#&lt;/a&gt; 函数&lt;sub class=&#34;red&#34;&gt; 2&lt;/sub&gt;&lt;/h2&gt;
&lt;p&gt;&lt;img data-src=&#34;https://cdn.jsdelivr.net/gh/0000rookie/imgs/2022051939.png&#34; alt=&#34;&#34; width=&#34;20%&#34; height=&#34;20%&#34;&gt;&lt;/p&gt;
&lt;figure class=&#34;highlight python&#34;&gt;&lt;figcaption data-lang=&#34;python&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr class=&#34;marked&#34;&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;import&lt;/span&gt; numpy &lt;span class=&#34;token keyword&#34;&gt;as&lt;/span&gt; np&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr class=&#34;marked&#34;&gt;&lt;td data-num=&#34;2&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;import&lt;/span&gt; matplotlib&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;pyplot &lt;span class=&#34;token keyword&#34;&gt;as&lt;/span&gt; plt&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr class=&#34;marked&#34;&gt;&lt;td data-num=&#34;3&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr class=&#34;marked&#34;&gt;&lt;td data-num=&#34;4&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;def&lt;/span&gt; &lt;span class=&#34;token function&#34;&gt;func&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;x&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;:&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr class=&#34;marked&#34;&gt;&lt;td data-num=&#34;5&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token keyword&#34;&gt;return&lt;/span&gt; np&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;cos&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token number&#34;&gt;2&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;*&lt;/span&gt;np&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;pi&lt;span class=&#34;token operator&#34;&gt;*&lt;/span&gt;x&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;*&lt;/span&gt;np&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;exp&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;-&lt;/span&gt;x&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;+&lt;/span&gt;&lt;span class=&#34;token number&#34;&gt;1&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr class=&#34;marked&#34;&gt;&lt;td data-num=&#34;6&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;left_x &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;token builtin&#34;&gt;int&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token builtin&#34;&gt;input&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token string&#34;&gt;&#34;请输入下限值：&#34;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr class=&#34;marked&#34;&gt;&lt;td data-num=&#34;7&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;right_x &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;token builtin&#34;&gt;int&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token builtin&#34;&gt;input&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token string&#34;&gt;&#34;请输入上限值：&#34;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr class=&#34;marked&#34;&gt;&lt;td data-num=&#34;8&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;x &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; np&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;arange&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;left_x&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt;right_x&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt;&lt;span class=&#34;token number&#34;&gt;0.01&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt; &lt;span class=&#34;token comment&#34;&gt;# 设置 X 的值&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr class=&#34;marked&#34;&gt;&lt;td data-num=&#34;9&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;y &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; func&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;x&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt; 			&lt;span class=&#34;token comment&#34;&gt;# 设置 Y 的值，一个 Y 都有一个 X 与他对应&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr class=&#34;marked&#34;&gt;&lt;td data-num=&#34;10&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;plt&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;xlim&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;left_x&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt;right_x&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt; 	&lt;span class=&#34;token comment&#34;&gt;# 设置 X 轴的范围&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr class=&#34;marked&#34;&gt;&lt;td data-num=&#34;11&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;plt&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;ylim&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;-&lt;/span&gt;&lt;span class=&#34;token number&#34;&gt;15000&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt;&lt;span class=&#34;token number&#34;&gt;25000&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;			 &lt;span class=&#34;token comment&#34;&gt;# 设置 Y 轴的范围&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr class=&#34;marked&#34;&gt;&lt;td data-num=&#34;12&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;plt&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;plot&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;x&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt;y&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt; 			&lt;span class=&#34;token comment&#34;&gt;# 将 X、Y 的值添加到面板中&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr class=&#34;marked&#34;&gt;&lt;td data-num=&#34;13&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;plt&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;show&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;			&lt;span class=&#34;token comment&#34;&gt;# 显示面板&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;

 &lt;h2 id=&#34;python散点图&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#python散点图&#34;&gt;#&lt;/a&gt; python 散点图&lt;/h2&gt;
&lt;h3 id=&#34;编写思路&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#编写思路&#34;&gt;#&lt;/a&gt; 编写思路&lt;/h3&gt;
&lt;h4 id=&#34;单个画板思路&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#单个画板思路&#34;&gt;#&lt;/a&gt; 单个画板思路&lt;/h4&gt;
&lt;ol&gt;
&lt;li&gt;导入相关模块&lt;/li&gt;
&lt;li&gt;获取数据为列表格式 (这是 &lt;code&gt;Y&lt;/code&gt;  的值，每一个 &lt;code&gt;X&lt;/code&gt;  都能找到一个对应的 &lt;code&gt;Y&lt;/code&gt;  值，称为函数)&lt;/li&gt;
&lt;li&gt;设置颜色 (可选)&lt;/li&gt;
&lt;li&gt;添加画板&lt;/li&gt;
&lt;li&gt;设置 &lt;code&gt;Ｘ&lt;/code&gt; 轴、 &lt;code&gt;Ｙ&lt;/code&gt; 轴长度&lt;/li&gt;
&lt;li&gt;设置 &lt;code&gt;X&lt;/code&gt;  的数据&lt;/li&gt;
&lt;li&gt;给画板添加数据&lt;/li&gt;
&lt;li&gt;显示画板&lt;/li&gt;
&lt;/ol&gt;
&lt;h4 id=&#34;多个画板思路&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#多个画板思路&#34;&gt;#&lt;/a&gt; 多个画板思路&lt;/h4&gt;
&lt;ol&gt;
&lt;li&gt;
&lt;p&gt;导入香相关模块&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;获取 &lt;code&gt;lis&lt;/code&gt;  数据为列表格式 (这是 &lt;code&gt;Y&lt;/code&gt;  的值，每一个 &lt;code&gt;X&lt;/code&gt;  都能找到一个对应的 &lt;code&gt;Y&lt;/code&gt;  值，称为函数)&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;设置颜色 (可选)&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;添加 &lt;code&gt;子图1-子图n&lt;/code&gt;  并设置 &lt;code&gt;X&lt;/code&gt; 、 &lt;code&gt;Y&lt;/code&gt;  轴长度&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;设置 &lt;code&gt;X&lt;/code&gt;  的数据&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;添加画板&lt;/p&gt;
&lt;figure class=&#34;highlight python&#34;&gt;&lt;figcaption data-lang=&#34;python&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr class=&#34;marked&#34;&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;for&lt;/span&gt; i &lt;span class=&#34;token keyword&#34;&gt;in&lt;/span&gt; &lt;span class=&#34;token builtin&#34;&gt;range&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token builtin&#34;&gt;len&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;lis&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;:&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr class=&#34;marked&#34;&gt;&lt;td data-num=&#34;2&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    ax1&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;scatter&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;x&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt;lis&lt;span class=&#34;token punctuation&#34;&gt;[&lt;/span&gt;i&lt;span class=&#34;token punctuation&#34;&gt;]&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt;c&lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt;colors&lt;span class=&#34;token punctuation&#34;&gt;[&lt;/span&gt;i&lt;span class=&#34;token punctuation&#34;&gt;]&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;展示画板&lt;/p&gt;
&lt;/li&gt;
&lt;/ol&gt;
&lt;h3 id=&#34;源码&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#源码&#34;&gt;#&lt;/a&gt; 源码&lt;/h3&gt;
&lt;figure class=&#34;highlight python&#34;&gt;&lt;figcaption data-lang=&#34;python&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr class=&#34;marked&#34;&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;import&lt;/span&gt; numpy &lt;span class=&#34;token keyword&#34;&gt;as&lt;/span&gt; np&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr class=&#34;marked&#34;&gt;&lt;td data-num=&#34;2&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;import&lt;/span&gt; matplotlib&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;pyplot &lt;span class=&#34;token keyword&#34;&gt;as&lt;/span&gt; plt&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr class=&#34;marked&#34;&gt;&lt;td data-num=&#34;3&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token comment&#34;&gt;# 从 data.csv 文件读取四列数据，结果返回是一个类似列表的数据，但类型不是列表，可当它是列表使用&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr class=&#34;marked&#34;&gt;&lt;td data-num=&#34;4&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;opening&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt;top&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt;bottom&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt;closing&lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt;np&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;loadtxt&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token string&#34;&gt;&#39;data.csv&#39;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; delimiter&lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt;&lt;span class=&#34;token string&#34;&gt;&#39;,&#39;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; usecols&lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token number&#34;&gt;3&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt;&lt;span class=&#34;token number&#34;&gt;4&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt;&lt;span class=&#34;token number&#34;&gt;5&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt;&lt;span class=&#34;token number&#34;&gt;6&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; unpack&lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt;&lt;span class=&#34;token boolean&#34;&gt;True&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr class=&#34;marked&#34;&gt;&lt;td data-num=&#34;5&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr class=&#34;marked&#34;&gt;&lt;td data-num=&#34;6&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token comment&#34;&gt;# 将数据封装为列表，便于将数据循环添加进画板&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr class=&#34;marked&#34;&gt;&lt;td data-num=&#34;7&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;lis &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;[&lt;/span&gt;opening&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt;top&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt;bottom&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt;closing&lt;span class=&#34;token punctuation&#34;&gt;]&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr class=&#34;marked&#34;&gt;&lt;td data-num=&#34;8&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;colors &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;[&lt;/span&gt;&lt;span class=&#34;token string&#34;&gt;&#39;green&#39;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt;&lt;span class=&#34;token string&#34;&gt;&#39;red&#39;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt;&lt;span class=&#34;token string&#34;&gt;&#39;b&#39;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt;&lt;span class=&#34;token string&#34;&gt;&#39;k&#39;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;]&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr class=&#34;marked&#34;&gt;&lt;td data-num=&#34;9&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr class=&#34;marked&#34;&gt;&lt;td data-num=&#34;10&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;fig1 &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; plt&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;figure&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token number&#34;&gt;2&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt; 					&lt;span class=&#34;token comment&#34;&gt;# 可有可无&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr class=&#34;marked&#34;&gt;&lt;td data-num=&#34;11&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;ax1 &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; plt&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;subplot&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token number&#34;&gt;211&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt;ylim&lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token number&#34;&gt;330&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt;&lt;span class=&#34;token number&#34;&gt;370&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt;xlim&lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;-&lt;/span&gt;&lt;span class=&#34;token number&#34;&gt;5&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt;&lt;span class=&#34;token number&#34;&gt;35&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt; &lt;span class=&#34;token comment&#34;&gt;# 添加上子图 211&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr class=&#34;marked&#34;&gt;&lt;td data-num=&#34;12&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;ax2&lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt;plt&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;subplot&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token number&#34;&gt;212&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt; 				&lt;span class=&#34;token comment&#34;&gt;# 添加下子图 212&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr class=&#34;marked&#34;&gt;&lt;td data-num=&#34;13&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;x &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; np&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;arange&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token number&#34;&gt;0&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt;&lt;span class=&#34;token number&#34;&gt;30&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt; 				&lt;span class=&#34;token comment&#34;&gt;# 设置 x 轴&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr class=&#34;marked&#34;&gt;&lt;td data-num=&#34;14&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;for&lt;/span&gt; i &lt;span class=&#34;token keyword&#34;&gt;in&lt;/span&gt; &lt;span class=&#34;token builtin&#34;&gt;range&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token builtin&#34;&gt;len&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;lis&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;:&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr class=&#34;marked&#34;&gt;&lt;td data-num=&#34;15&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    ax1&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;scatter&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;x&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt;lis&lt;span class=&#34;token punctuation&#34;&gt;[&lt;/span&gt;i&lt;span class=&#34;token punctuation&#34;&gt;]&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt;c&lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt;colors&lt;span class=&#34;token punctuation&#34;&gt;[&lt;/span&gt;i&lt;span class=&#34;token punctuation&#34;&gt;]&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt; &lt;span class=&#34;token comment&#34;&gt;# 给上子图添加数据&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr class=&#34;marked&#34;&gt;&lt;td data-num=&#34;16&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    ax2&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;plot&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;x&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt;lis&lt;span class=&#34;token punctuation&#34;&gt;[&lt;/span&gt;i&lt;span class=&#34;token punctuation&#34;&gt;]&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt;c&lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt;colors&lt;span class=&#34;token punctuation&#34;&gt;[&lt;/span&gt;i&lt;span class=&#34;token punctuation&#34;&gt;]&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt; &lt;span class=&#34;token comment&#34;&gt;# 给下子图添加数据&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr class=&#34;marked&#34;&gt;&lt;td data-num=&#34;17&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;plt&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;show&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt; 					&lt;span class=&#34;token comment&#34;&gt;# 展示画板&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;p&gt;&lt;img data-src=&#34;https://cdn.jsdelivr.net/gh/0000rookie/imgs/2022053015.jpeg&#34; alt=&#34;&#34;&gt;&lt;/p&gt;
